/* adm-item-mixshipitemimposs-sql-oracle.xml - selectMixShipItemImpossHd */ #{GRIDPAGING_ROWNUMTYPE_TOP} SELECT AA.* FROM ( SELECT '0' AS CHK ,A.OWKEY ,O.OWNM ,A.GRPID ,A.GRPNM ,A.GRPFLAG ,A.CMT ,A.INSERTDATE ,A.UPDATEDATE , A.INSERTURKEY , A.UPDATEURKEY ,A.DELYN ,'YESORNO' || ';' || A.DELYN AS DELYN_DESC FROM TADMIN_MST_NOMIX_HD A INNER JOIN TADMIN_MST_OW O ON A.OWKEY = O.OWKEY ) AA WHERE #{SEARCH_CONDITION}
ORDER BY #{colName} DESC
ORDER BY #{colName} ASC
ORDER BY UPDATEDATE DESC
#{GRIDPAGING_ROWNUMTYPE_BOTTOM}

/* adm-item-mixshipitemimposs-sql-oracle.xml - checkmixShipItemImposso */
	SELECT count(1)
	  FROM TADMIN_MST_NOMIX_HD 
	  WHERE GRPNM = #{grpnm}
	    AND OWKEY = #{owkey}

	/* adm-item-mixshipitemimposs-sql-oracle.xml - checkDetailmixShipItemImposso */
		SELECT count(1)
		  FROM TADMIN_MST_NOMIX_HD H
		  INNER JOIN TADMIN_MST_NOMIX_DT D
		  		  ON H.GRPID = D.GRPID
				 AND H.OWKEY = D.OWKEY
		  WHERE D.GRPID = #{grpid}
		    AND H.GRPFLAG = #{grpflag}
		    AND H.OWKEY		= #{owkey}

    	 	AND D.ICGRPKEY = #{icgrpkey}


    	 	AND D.ICKEY = #{ickey}

mapper.insert:
		/* adm-item-mixshipitemimposs-sql-oracle.xml - insertMixShipItemImposInfo */

       SELECT (CASE COUNT(GRPID) WHEN 0 THEN 1 ELSE MAX(CAST(GRPID AS NUMERIC))+1 END)::TEXT AS GRPID
         FROM TADMIN_MST_NOMIX_HD 
        WHERE OWKEY= #{owkey}


		INSERT INTO TADMIN_MST_NOMIX_HD
		(
		      GRPID
		    , GRPNM
		   	, OWKEY
		   	, GRPFLAG
		   	, CMT
		    , INSERTDATE
			, INSERTURKEY
   		  	, UPDATEDATE
			, UPDATEURKEY
			, DELYN
		)
		VALUES
		(
		     #{id}
		    ,#{grpnm}
		    ,#{owkey}
		    ,#{grpflag}
		    ,#{cmt}
			,#{sysdate}
			,#{surkey}
			,#{sysdate}
			,#{surkey}
			,#{delyn}
		)

