/* adm-item-mixshipitemimposs-sql-oracle.xml - updateMixShipItemImposInfo */
UPDATE TADMIN_MST_NOMIX_HD 
   SET GRPNM = #{grpnm}
   	 , CMT 	= #{cmt}
	 , UPDATEDATE   = #{sysdate}
	 , UPDATEURKEY  = #{surkey}		
 WHERE GRPID  = #{grpid}

/* adm-item-mixshipitemimposs-sql-oracle.xml - deleteMixShipItemImposInfo */

UPDATE TADMIN_MST_NOMIX_HD 
   SET DELYN ='Y'
	 , UPDATEDATE   = #{sysdate}
	 , UPDATEURKEY  = #{surkey}		
 WHERE GRPID  = #{grpid}

